INSERT INTO industry_kpi (industry_id, key, name, definition, why_it_matters, unit, signal_type, update_frequency, source_name, source_url, affected_companies, affected_products) VALUES ('rubber-gloves', 'asp_my', 'Malaysian glove ASP', 'Average selling price of nitrile examination gloves exported from Malaysia, quoted per 1,000 pieces in USD.', 'ASP is the revenue side of the glove margin equation. Malaysian makers are price takers in a commoditised market, so ASP moves earnings faster than volume does — a cycle turn shows up here before it shows up in reported results.', 'USD / 1000 pcs', 'leading', 'monthly', 'MARGMA (Malaysian Rubber Glove Manufacturers Association)', 'https://www.margma.com.my/', 'top-glove,hartalega,kossan,supermax,careplus,comfort-gloves,hextar-healthcare', 'Nitrile examination gloves,Latex examination gloves') ON CONFLICT (industry_id, key) DO UPDATE SET name = EXCLUDED.name, definition = EXCLUDED.definition, why_it_matters = EXCLUDED.why_it_matters, unit = EXCLUDED.unit, signal_type = EXCLUDED.signal_type, update_frequency = EXCLUDED.update_frequency, source_name = EXCLUDED.source_name, source_url = EXCLUDED.source_url, affected_companies = EXCLUDED.affected_companies, affected_products = EXCLUDED.affected_products;
INSERT INTO industry_kpi (industry_id, key, name, definition, why_it_matters, unit, signal_type, update_frequency, source_name, source_url, affected_companies, affected_products) VALUES ('rubber-gloves', 'nbr_latex', 'NBR latex cost', 'Spot cost of nitrile butadiene rubber latex, the primary raw material for nitrile gloves, quoted per tonne in USD.', 'NBR latex is the largest single input cost. Because ASP and NBR move on different drivers — glove demand versus petrochemical feedstock — the SPREAD between them, not either level, is what determines margin. This is the cost side of that spread.', 'USD / tonne', 'leading', 'monthly', 'glove-tracker industry benchmarks', NULL, 'top-glove,hartalega,kossan,supermax,careplus,comfort-gloves,hextar-healthcare', 'Nitrile examination gloves') ON CONFLICT (industry_id, key) DO UPDATE SET name = EXCLUDED.name, definition = EXCLUDED.definition, why_it_matters = EXCLUDED.why_it_matters, unit = EXCLUDED.unit, signal_type = EXCLUDED.signal_type, update_frequency = EXCLUDED.update_frequency, source_name = EXCLUDED.source_name, source_url = EXCLUDED.source_url, affected_companies = EXCLUDED.affected_companies, affected_products = EXCLUDED.affected_products;
INSERT INTO industry_kpi (industry_id, key, name, definition, why_it_matters, unit, signal_type, update_frequency, source_name, source_url, affected_companies, affected_products) VALUES ('semis-memory', 'hbm_share', 'HBM share of DRAM revenue', 'High-bandwidth memory revenue as a proportion of total DRAM revenue for a maker.', 'HBM carries structurally higher margin than commodity DRAM and is sold on long-term agreements rather than spot. A rising HBM share therefore changes the earnings quality of a memory maker, not just its level — the same revenue becomes less cyclical.', '%', 'lagging', 'quarterly', 'Company quarterly filings and investor presentations', NULL, 'sk-hynix,micron', 'HBM,DRAM') ON CONFLICT (industry_id, key) DO UPDATE SET name = EXCLUDED.name, definition = EXCLUDED.definition, why_it_matters = EXCLUDED.why_it_matters, unit = EXCLUDED.unit, signal_type = EXCLUDED.signal_type, update_frequency = EXCLUDED.update_frequency, source_name = EXCLUDED.source_name, source_url = EXCLUDED.source_url, affected_companies = EXCLUDED.affected_companies, affected_products = EXCLUDED.affected_products;
INSERT INTO industry_knowledge (industry_id, section, content, kind, source_url, confidence, as_of) SELECT 'rubber-gloves', 'overview', 'Malaysia is the world''s largest exporter of rubber examination gloves. The industry is dominated by a small number of listed manufacturers whose output is commoditised, sold largely into healthcare distribution channels, and priced in USD while much of the cost base is in MYR.', 'fact', 'https://www.margma.com.my/', 0.9, '2026-07-21' WHERE NOT EXISTS (SELECT 1 FROM industry_knowledge WHERE industry_id = 'rubber-gloves' AND section = 'overview' AND content = 'Malaysia is the world''s largest exporter of rubber examination gloves. The industry is dominated by a small number of listed manufacturers whose output is commoditised, sold largely into healthcare distribution channels, and priced in USD while much of the cost base is in MYR.');
INSERT INTO industry_knowledge (industry_id, section, content, kind, source_url, confidence, as_of) SELECT 'rubber-gloves', 'products', 'Nitrile examination gloves (the dominant product by volume and the basis of the ASP benchmark), latex examination gloves, surgical gloves, and vinyl gloves. Nitrile has displaced latex in most developed-market healthcare use on allergen grounds.', 'fact', 'https://www.margma.com.my/', 0.85, '2026-07-21' WHERE NOT EXISTS (SELECT 1 FROM industry_knowledge WHERE industry_id = 'rubber-gloves' AND section = 'products' AND content = 'Nitrile examination gloves (the dominant product by volume and the basis of the ASP benchmark), latex examination gloves, surgical gloves, and vinyl gloves. Nitrile has displaced latex in most developed-market healthcare use on allergen grounds.');
INSERT INTO industry_knowledge (industry_id, section, content, kind, source_url, confidence, as_of) SELECT 'rubber-gloves', 'pricing', 'Two tracked indicators: Malaysian glove ASP (USD per 1,000 pieces) and NBR latex cost (USD per tonne). Atlas derives a margin cycle signal from the ratio between them, indexed to 2019-09 = 100. The spread, not either level alone, drives manufacturer margin.', 'fact', 'https://www.margma.com.my/', 1, '2026-07-21' WHERE NOT EXISTS (SELECT 1 FROM industry_knowledge WHERE industry_id = 'rubber-gloves' AND section = 'pricing' AND content = 'Two tracked indicators: Malaysian glove ASP (USD per 1,000 pieces) and NBR latex cost (USD per tonne). Atlas derives a margin cycle signal from the ratio between them, indexed to 2019-09 = 100. The spread, not either level alone, drives manufacturer margin.');
INSERT INTO industry_knowledge (industry_id, section, content, kind, source_url, confidence, as_of) SELECT 'rubber-gloves', 'suppliers', 'Upstream inputs are NBR latex (petrochemical-derived, priced off butadiene and acrylonitrile) and natural rubber latex. Input pricing is therefore tied to petrochemical feedstock rather than to glove demand, which is why the ASP-to-cost spread widens and narrows independently of volume.', 'fact', NULL, 0.75, '2026-07-21' WHERE NOT EXISTS (SELECT 1 FROM industry_knowledge WHERE industry_id = 'rubber-gloves' AND section = 'suppliers' AND content = 'Upstream inputs are NBR latex (petrochemical-derived, priced off butadiene and acrylonitrile) and natural rubber latex. Input pricing is therefore tied to petrochemical feedstock rather than to glove demand, which is why the ASP-to-cost spread widens and narrows independently of volume.');
INSERT INTO industry_knowledge (industry_id, section, content, kind, source_url, confidence, as_of) SELECT 'rubber-gloves', 'kpis', 'Tracked industry KPIs: Malaysian glove ASP (leading, monthly) and NBR latex cost (leading, monthly). Both are operational drivers specific to this industry rather than generic financial ratios.', 'fact', 'https://www.margma.com.my/', 1, '2026-07-21' WHERE NOT EXISTS (SELECT 1 FROM industry_knowledge WHERE industry_id = 'rubber-gloves' AND section = 'kpis' AND content = 'Tracked industry KPIs: Malaysian glove ASP (leading, monthly) and NBR latex cost (leading, monthly). Both are operational drivers specific to this industry rather than generic financial ratios.');
INSERT INTO industry_knowledge (industry_id, section, content, kind, source_url, confidence, as_of) SELECT 'semis-memory', 'overview', 'Memory divides into DRAM (including high-bandwidth memory, HBM) and NAND flash. The segment is historically deeply cyclical, with pricing set by the balance between capacity additions and demand. HBM has emerged as a structurally tighter sub-segment because it is sold on long-term agreements into AI accelerator programmes.', 'fact', NULL, 0.8, '2026-07-21' WHERE NOT EXISTS (SELECT 1 FROM industry_knowledge WHERE industry_id = 'semis-memory' AND section = 'overview' AND content = 'Memory divides into DRAM (including high-bandwidth memory, HBM) and NAND flash. The segment is historically deeply cyclical, with pricing set by the balance between capacity additions and demand. HBM has emerged as a structurally tighter sub-segment because it is sold on long-term agreements into AI accelerator programmes.');
INSERT INTO industry_knowledge (industry_id, section, content, kind, source_url, confidence, as_of) SELECT 'semis-memory', 'customers', 'HBM output is concentrated into a small number of AI accelerator programmes; Atlas records the supply relationships it can source in the knowledge graph (see /v1/graph). Customer concentration is therefore high, and a single programme''s capex cycle propagates directly into memory maker revenue.', 'fact', NULL, 0.7, '2026-07-21' WHERE NOT EXISTS (SELECT 1 FROM industry_knowledge WHERE industry_id = 'semis-memory' AND section = 'customers' AND content = 'HBM output is concentrated into a small number of AI accelerator programmes; Atlas records the supply relationships it can source in the knowledge graph (see /v1/graph). Customer concentration is therefore high, and a single programme''s capex cycle propagates directly into memory maker revenue.');
